import json
import sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    command = inp.get("command", "")

    # Block plain "pnpm test" which times out in non-interactive context
    if command.strip() == "pnpm test":
        msg = "This project's 'pnpm test' hangs in non-interactive contexts (120s timeout). Use 'pnpm test:ci' instead for CI runs."
        print(msg, file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, subprocess

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    try:
        # Check if formatting is needed
        check = subprocess.run(
            ["ruff", "format", file_path, "--check"],
            capture_output=True,
            text=True,
            timeout=10
        )

        if check.returncode != 0:  # Changes needed
            # Apply formatting
            subprocess.run(["ruff", "format", file_path], capture_output=True, timeout=10)
            print(f"Do not stop — auto-formatted {file_path} per project convention", file=sys.stderr)
    except FileNotFoundError:
        return 0  # ruff not installed
    except Exception:
        return 0

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    # Only check Edit on TypeScript/JavaScript files
    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith((".ts", ".tsx", ".js", ".jsx")):
        return 0

    old_str = inp.get("old_string", "")

    # Check if the edit touches an export statement
    if "export " not in old_str:
        return 0

    # This looks like an export rename — warn the model
    msg = "REQUIRED FOLLOW-UP: You may have renamed an exported identifier. Use Grep to search the codebase for all references. Fix or update each reference as needed. Do not stop until done."
    print(msg, file=sys.stderr)
    return 0

if __name__ == "__main__":
    sys.exit(main())

