#!/usr/bin/env python3
"""Run pytest after any Edit to a .py file to catch errors early."""
import json, sys, subprocess

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool != "Edit":
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    cwd = ev.get("cwd", ".")

    # Run pytest to catch errors early
    try:
        result = subprocess.run(
            ["python", "-m", "pytest", "-xvs", "--tb=short"],
            capture_output=True, text=True, timeout=30, cwd=cwd
        )
        if result.returncode != 0:
            print(f"BLOCKING: Tests failed after editing {file_path}. Fix all failures before proceeding.\n{result.stdout}", file=sys.stderr)
            return 2
    except FileNotFoundError:
        return 0
    except Exception:
        return 0

    return 0

if __name__ == "__main__":
    sys.exit(main())
